const express = require('express');
const jwt = require('jsonwebtoken');

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';

const jwtVerifyMiddleware = (req, res, next) => {
  try {
    const authHeader = req.headers.authorization;
    
    if (!authHeader) {
      return res.status(401).json({ error: 'No authorization header provided' });
    }

    const parts = authHeader.split(' ');
    
    if (parts.length !== 2 || parts[0] !== 'Bearer') {
      return res.status(401).json({ error: 'Invalid authorization header format. Use: Bearer <token>' });
    }

    const token = parts[1];

    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ['HS256'],
      complete: false,
      clockTolerance: 0,
      ignoreExpiration: false,
      ignoreNotBefore: false
    });

    req.user = decoded;
    next();
  } catch (error) {
    if (error.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token has expired' });
    }
    if (error.name === 'JsonWebTokenError') {
      return res.status(401).json({ error: 'Invalid token' });
    }
    if (error.name === 'NotBeforeError') {
      return res.status(401).json({ error: 'Token not yet valid' });
    }
    return res.status(401).json({ error: 'Authentication failed' });
  }
};

const app = express();
app.use(express.json());

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  
  if (username === 'demo' && password === 'password') {
    const token = jwt.sign(
      { 
        userId: 1, 
        username: 'demo',
        role: 'user'
      },
      JWT_SECRET,
      { 
        expiresIn: '1h',
        algorithm: 'HS256'
      }
    );
    
    return res.json({ token });
  }
  
  res.status(401).json({ error: 'Invalid credentials' });
});

app.get('/protected', jwtVerifyMiddleware, (req, res) => {
  res.json({ 
    message: 'Access granted to protected route',
    user: req.user
  });
});

app.get('/profile', jwtVerifyMiddleware, (req, res) => {
  res.json({
    userId: req.user.userId,
    username: req.user.username,
    role: req.user.role
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = { jwtVerifyMiddleware, app };